const allItems = $input.all();
const parseItem = allItems[0]?.json || {};
const parsedContent = parseItem.markdown || parseItem.text || '';

const askItem = allItems[1]?.json || {};
const qaAnalysis = askItem.answer || askItem.markdown || askItem.text || '';

// Combine both for searching
const fullText = parsedContent + '\n' + qaAnalysis;

const triggerData = $('New Document').item.json;
const fileName = triggerData.name || 'unknown';
const fileId   = triggerData.id   || '';

// ── Document type ──────────────────────────────────────────────
let docType = 'Unknown';
const ft = fullText.toLowerCase();
if (ft.includes('closing disclosure'))      docType = 'Closing Disclosure';
else if (ft.includes('loan estimate'))       docType = 'Loan Estimate';
else if (ft.includes('home inspection'))     docType = 'Home Inspection';
else if (ft.includes('purchase agreement'))  docType = 'Purchase Agreement';
else if (ft.includes('appraisal'))           docType = 'Appraisal';
else if (ft.includes('title insurance'))     docType = 'Title Insurance';
else if (ft.includes('mortgage note'))       docType = 'Mortgage Note';
else if (ft.includes('deed of trust') || ft.includes('warranty deed')) docType = 'Deed';
else if (ft.includes('hoa') || ft.includes('homeowner'))               docType = 'HOA Documents';

// ── Helper: extract first dollar amount after a label ──────────
function extractAmount(text, patterns) {
  for (const pattern of patterns) {
    const m = text.match(pattern);
    if (m) {
      const val = parseFloat(m[1].replace(/,/g, ''));
      if (!isNaN(val) && val > 0) return val;
    }
  }
  return 0;
}

// ── Purchase price ─────────────────────────────────────────────
const purchasePrice = extractAmount(fullText, [
  /purchase price\s*[:\|]?\s*\$?([\d,]+(?:\.\d+)?)/i,
  /sale price\s*[:\|]?\s*\$?([\d,]+(?:\.\d+)?)/i,
  /contract price\s*[:\|]?\s*\$?([\d,]+(?:\.\d+)?)/i,
]);

// ── Loan amount ────────────────────────────────────────────────
const loanAmount = extractAmount(fullText, [
  /loan amount\s*[:\|]?\s*\$?([\d,]+(?:\.\d+)?)/i,
  /amount financed\s*[:\|]?\s*\$?([\d,]+(?:\.\d+)?)/i,
]);

// ── Monthly payment — must be < purchase price and look like a payment ──
const monthlyPayment = extractAmount(fullText, [
  /(?:total )?monthly payment\s*[:\|]?\s*\$?([1-9]\d{2,4}(?:\.\d{2})?)/i,
  /principal\s*(?:&|and)\s*interest\s*[:\|]?\s*\$?([1-9]\d{2,4}(?:\.\d{2})?)/i,
  /estimated monthly payment\s*[:\|]?\s*\$?([1-9]\d{2,4}(?:\.\d{2})?)/i,
  /\$([1-9]\d{2,4}\.\d{2})\s*per month/i,
]);

// ── Interest rate ──────────────────────────────────────────────
let interestRate = 'N/A';
const rateM = fullText.match(/interest rate\s*[:\|]?\s*(\d+\.?\d*)\s*%?/i);
if (rateM) interestRate = rateM[1];

// ── Closing costs ──────────────────────────────────────────────
const closingCosts = extractAmount(fullText, [
  /closing costs\s*[:\|]?\s*\$?([\d,]+(?:\.\d+)?)/i,
  /total closing costs\s*[:\|]?\s*\$?([\d,]+(?:\.\d+)?)/i,
  /J\.?\s*Total Closing Costs[\s\S]{0,50}?([\d,]+(?:\.\d+)?)/i,
]);

// ── Cash to close ──────────────────────────────────────────────
const cashToClose = extractAmount(fullText, [
  /cash to close\s*[:\|]?\s*\$?([\d,]+(?:\.\d+)?)/i,
  /total cash to close\s*[:\|]?\s*\$?([\d,]+(?:\.\d+)?)/i,
  /due (?:from|at) (?:borrower|closing)\s*[:\|]?\s*\$?([\d,]+(?:\.\d+)?)/i,
]);

// ── Closing date ───────────────────────────────────────────────
let closingDate = 'N/A';
const dateM = fullText.match(/closing date\s*[:\|]?\s*(\d{1,2}[\/-]\d{1,2}[\/-]\d{2,4}|[A-Z][a-z]+ \d{1,2},? \d{4})/i);
if (dateM) closingDate = dateM[1];

// ── Property address ───────────────────────────────────────────
let propertyAddress = 'N/A';
const addrM = fullText.match(/property address\s*[:\|]?\s*([^\n]{5,80})/i) ||
              fullText.match(/subject property\s*[:\|]?\s*([^\n]{5,80})/i) ||
              fullText.match(/(\d+\s+[A-Za-z][^,\n]{3,40},\s*[A-Za-z\s]+,\s*[A-Z]{2}\s*\d{5})/);
if (addrM) propertyAddress = addrM[1].trim().substring(0, 100);

// ── Issues ─────────────────────────────────────────────────────
const issues = [];
const flagPatterns = [
  /red flag[:\s]+([^.\n]{10,150})/gi,
  /major (?:issue|concern)[:\s]+([^.\n]{10,150})/gi,
  /critical[:\s]+([^.\n]{10,150})/gi,
  /repairs? (?:needed|required)[:\s]+([^.\n]{10,150})/gi,
];
flagPatterns.forEach(p => {
  let m;
  while ((m = p.exec(qaAnalysis)) !== null) {
    issues.push(m[1].trim());
  }
});
const issueCount = issues.length;

// ── Action required ────────────────────────────────────────────
const actionRequired = /immediat|deadline|action required|must sign|expires/i.test(fullText);

return [{ json: {
  fileName, fileId,
  documentType:    docType,
  propertyAddress,
  purchasePrice,
  loanAmount,
  monthlyPayment,
  interestRate,
  closingCosts,
  cashToClose,
  closingDate,
  issueCount,
  issues: issues.join('; ') || 'None identified',
  actionRequired,
  processedAt: new Date().toISOString()
}}];

